import"./style-B4IgR0yf.js";document.addEventListener("DOMContentLoaded",()=>{const o=document.getElementById("submitButton"),t=document.getElementById("issue"),n=document.getElementById("response");o.addEventListener("click",async i=>{i.preventDefault();const s=t.value.trim();if(!s){alert("Please enter an issue before submitting.");return}try{const e=await fetch("/api/message",{method:"POST",credentials:"include",headers:{"Content-Type":"application/json"},body:JSON.stringify({text:s})});if(!e.ok)throw new Error("Server error");const r=await e.json();n?n.innerText=r.reply:alert("Server says: "+r.reply),t.value=""}catch(e){console.error("Error submitting issue:",e),alert("Something went wrong while submitting the issue.")}})});
